var surah044 = {
  number: 44,
  nameArabic: "ad-Dukhan",
  nameEnglish: "Ad-Dukhan",
  meaning: "The Smoke",
  totalAyahs: 59,
  ayahs: [
    { number: 1, arabic: "حمٓ", transliteration: "Hameem", transliterationB: "Haa Meeem", english: "Ha-Mim", romanUrdu: "Haa Meem" },
    { number: 2, arabic: "وَٱلْكِتَٰبِ ٱلْمُبِينِ", transliteration: "Waalkitabi almubeeni", transliterationB: "Wal Kitaabil Mubeen", english: "By the Book that makes things clear", romanUrdu: "Kasam hai is kitaab e Mubeen ki" },
    { number: 3, arabic: "إِنَّآ أَنزَلْنَٰهُ فِى لَيْلَةٍۢ مُّبَٰرَكَةٍ ۚ إِنَّا كُنَّا مُنذِرِينَ", transliteration: "Inna anzalnahu fee laylatin mubarakatin inna kunna munthireena", transliterationB: "Innaaa anzalnaahu fee lailatim mubaarakah; innaa kunnaa munzireen", english: "We sent it down during a Blessed Night: for We (ever) wish to warn (against Evil)", romanUrdu: "Ke humne isey ek badi khair o barakat wali raat mein nazil kiya hai, kyunke hum logon ko mutanabbeh (warning) karne ka irada rakhte thay" },
    { number: 4, arabic: "فِيهَا يُفْرَقُ كُلُّ أَمْرٍ حَكِيمٍ", transliteration: "Feeha yufraqu kullu amrin hakeemin", transliterationB: "Feehaa yufraqu kullu amrin hakeem", english: "In the (Night) is made distinct every affair of wisdom", romanUrdu: "Yeh woh raat thi jismein har maamle ka hakeemana faisla" },
    { number: 5, arabic: "أَمْرًۭا مِّنْ عِندِنَآ ۚ إِنَّا كُنَّا مُرْسِلِينَ", transliteration: "Amran min AAindina inna kunna mursileena", transliterationB: "Amram min 'indinaaa; innaa kunnaa mursileen", english: "By command, from Our Presence. For We (ever) send (revelations)", romanUrdu: "Hamare hukum se sadir kiya jata hai. Hum ek Rasool bhejne waley thay" },
    { number: 6, arabic: "رَحْمَةًۭ مِّن رَّبِّكَ ۚ إِنَّهُۥ هُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ", transliteration: "Rahmatan min rabbika innahu huwa alssameeAAu alAAaleemu", transliterationB: "Rahmatam mir rabbik; innahoo Huwas Samee'ul 'Aleem", english: "As Mercy from thy Lord: for He hears and knows (all things)", romanUrdu: "Tere Rubb ki rehmat ke taur par.Yaqeenan wahi sab kuch sunne aur jaanne wala hai" },
    { number: 7, arabic: "رَبِّ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَمَا بَيْنَهُمَآ ۖ إِن كُنتُم مُّوقِنِينَ", transliteration: "Rabbi alssamawati waalardi wama baynahuma in kuntum mooqineena", transliterationB: "Rabbis samaawaati wal ardi wa maa bainahumaa; in kuntum mooqineen", english: "The Lord of the heavens and the earth and all between them, if ye (but) have an assured faith", romanUrdu: "Aasmano aur zameen ka Rubb aur har us cheez ka Rubb jo Aasman o zameen ke darmiyan hai agar tum log waqaii yakeen rakhne waley ho" },
    { number: 8, arabic: "لَآ إِلَٰهَ إِلَّا هُوَ يُحْىِۦ وَيُمِيتُ ۖ رَبُّكُمْ وَرَبُّ ءَابَآئِكُمُ ٱلْأَوَّلِينَ", transliteration: "La ilaha illa huwa yuhyee wayumeetu rabbukum warabbu abaikumu alawwaleena", transliterationB: "Laaa ilaaha illaa Huwa yuhyee wa yumeetu Rabbukum wa Rabbu aabaaa'ikumul awwaleen", english: "There is no god but He: It is He Who gives life and gives death,- The Lord and Cherisher to you and your earliest ancestors", romanUrdu: "Koi maabood uske siwa nahin hai. Wahi zindagi ata karta hai aur wahi maut deta hai.Tumhara Rubb aur tumhare un aslaaf (forefathers) ka Rubb jo pehle guzar chuke hain" },
    { number: 9, arabic: "بَلْ هُمْ فِى شَكٍّۢ يَلْعَبُونَ", transliteration: "Bal hum fee shakkin yalAAaboona", transliterationB: "Bal hum fee shakkiny yal'aboon", english: "Yet they play about in doubt", romanUrdu: "(Magar fil-waqeh in logon ko yaqeen nahin hai) balke yeh apne shakk mein paday khel rahey hain" },
    { number: 10, arabic: "فَٱرْتَقِبْ يَوْمَ تَأْتِى ٱلسَّمَآءُ بِدُخَانٍۢ مُّبِينٍۢ", transliteration: "Fairtaqib yawma tatee alssamao bidukhanin mubeenin", transliterationB: "Fartaqib Yawma taatis samaaa'u bidukhaanim mubeen", english: "Then watch thou for the Day that the sky will bring forth a kind of smoke (or mist) plainly visible", romanUrdu: "Accha intezar karo us din ka jab aasman sareeh dhuwan (smoke) liye huey aayega" },
    { number: 11, arabic: "يَغْشَى ٱلنَّاسَ ۖ هَٰذَا عَذَابٌ أَلِيمٌۭ", transliteration: "Yaghsha alnnasa hatha AAathabun aleemun", transliterationB: "Yaghshan naasa haazaa 'azaabun aleem", english: "Enveloping the people: this will be a Penalty Grievous", romanUrdu: "Aur woh logon par chaa jayega, yeh hai dardnaak saza" },
    { number: 12, arabic: "رَّبَّنَا ٱكْشِفْ عَنَّا ٱلْعَذَابَ إِنَّا مُؤْمِنُونَ", transliteration: "Rabbana ikshif AAanna alAAathaba inna muminoona", transliterationB: "Rabbanak shif 'annal 'azaaba innaa mu'minoon", english: "(They will say:) \"Our Lord! remove the Penalty from us, for we do really believe", romanUrdu: "(Ab kehte hain ke) “ parwardigar , humpar se yeh azaab taal de, hum imaan laatey hain”" },
    { number: 13, arabic: "أَنَّىٰ لَهُمُ ٱلذِّكْرَىٰ وَقَدْ جَآءَهُمْ رَسُولٌۭ مُّبِينٌۭ", transliteration: "Anna lahumu alththikra waqad jaahum rasoolun mubeenun", transliterationB: "Annaa lahumuz zikraa wa qad jaaa'ahum Rasoolum mubeen", english: "How shall the message be (effectual) for them, seeing that an Messenger explaining things clearly has (already) come to them", romanUrdu: "Inki gaflat kahan dur hoti hai? Inka haal to yeh hai ke in ke paas Rasool e mubeen aa gaya" },
    { number: 14, arabic: "ثُمَّ تَوَلَّوْا۟ عَنْهُ وَقَالُوا۟ مُعَلَّمٌۭ مَّجْنُونٌ", transliteration: "Thumma tawallaw AAanhu waqaloo muAAallamun majnoonun", transliterationB: "Summaa tawallaw 'anhu wa qaaloo mu'allamum majnoon", english: "Yet they turn away from him and say: \"Tutored (by others), a man possessed", romanUrdu: "Phir bhi yeh uski taraf multafit na huey aur kaha ke “ yeh to sikhaya padaya bawla hai (well-tutored madman)”" },
    { number: 15, arabic: "إِنَّا كَاشِفُوا۟ ٱلْعَذَابِ قَلِيلًا ۚ إِنَّكُمْ عَآئِدُونَ", transliteration: "Inna kashifoo alAAathabi qaleelan innakum AAaidoona", transliterationB: "Innaa kaashiful 'azaabi qaleelaa; innakum 'aaa'indoon", english: "We shall indeed remove the Penalty for a while, (but) truly ye will revert (to your ways)", romanUrdu: "Hum zara azaab hataye detay hain, tum log phir wahi kuch karoge jo pehle kar rahe thay" },
    { number: 16, arabic: "يَوْمَ نَبْطِشُ ٱلْبَطْشَةَ ٱلْكُبْرَىٰٓ إِنَّا مُنتَقِمُونَ", transliteration: "Yawma nabtishu albatshata alkubra inna muntaqimoona", transliterationB: "Yawma nabtishul batsha tal kubraa innaa muntaqimoon", english: "One day We shall seize you with a mighty onslaught: We will indeed (then) exact Retribution", romanUrdu: "Jis roz hum badi zarb (assault) lagayenge woh din hoga jab hum tumse intiqaam lenge" },
    { number: 17, arabic: "۞ وَلَقَدْ فَتَنَّا قَبْلَهُمْ قَوْمَ فِرْعَوْنَ وَجَآءَهُمْ رَسُولٌۭ كَرِيمٌ", transliteration: "Walaqad fatanna qablahum qawma firAAawna wajaahum rasoolun kareemun", transliterationB: "Wa laqad fatannaa qablahum qawma Fir'awna wa jaaa'ahum Rasoolun kareem", english: "We did, before them, try the people of Pharaoh: there came to them a messenger most honourable", romanUrdu: "Hum insey pehle Firaun ki qaum ko isi aazmaish mein daal chuke hain. Unke paas ek nihayat shareef Rasool aaya" },
    { number: 18, arabic: "أَنْ أَدُّوٓا۟ إِلَىَّ عِبَادَ ٱللَّهِ ۖ إِنِّى لَكُمْ رَسُولٌ أَمِينٌۭ", transliteration: "An addoo ilayya AAibada Allahi innee lakum rasoolun ameenun", transliterationB: "An addooo ilaiya 'ibaadal laahi innee lakum Rasoolun ameen", english: "Saying: \"Restore to me the Servants of Allah: I am to you an messenger worthy of all trust", romanUrdu: "Aur usne kaha “Allah ke bandon ko mere hawale karo, main tumhare liye ek amanat-daar Rasool hoon" },
    { number: 19, arabic: "وَأَن لَّا تَعْلُوا۟ عَلَى ٱللَّهِ ۖ إِنِّىٓ ءَاتِيكُم بِسُلْطَٰنٍۢ مُّبِينٍۢ", transliteration: "Waan la taAAloo AAala Allahi innee ateekum bisultanin mubeenin", transliterationB: "Wa al laa ta'loo 'alal laahi innee aateekum bisultaanim mubeen", english: "And be not arrogant as against Allah: for I come to you with authority manifest", romanUrdu: "Allah ke muqable mein sarkashi na karo. Main tumhare saamne (apni maamuriyat ki) sareeh sanad (clear authority) pesh karta hoon" },
    { number: 20, arabic: "وَإِنِّى عُذْتُ بِرَبِّى وَرَبِّكُمْ أَن تَرْجُمُونِ", transliteration: "Wainnee AAuthtu birabbee warabbikum an tarjumooni", transliterationB: "Wa innee 'uztu bi Rabbee wa rabbikum an tarjumoon", english: "For me, I have sought safety with my Lord and your Lord, against your injuring me", romanUrdu: "Aur main apne Rubb aur tumhare Rubb ki panaah le chuka hoon issey ke tum mujhpar hamla-awar (attack) ho" },
    { number: 21, arabic: "وَإِن لَّمْ تُؤْمِنُوا۟ لِى فَٱعْتَزِلُونِ", transliteration: "Wain lam tuminoo lee faiAAtazilooni", transliterationB: "Wa il lam tu'minoo lee fa'taziloon", english: "If ye believe me not, at least keep yourselves away from me", romanUrdu: "Agar tum meri baat nahin maante to mujhpar haath daalne se baaz raho”" },
    { number: 22, arabic: "فَدَعَا رَبَّهُۥٓ أَنَّ هَٰٓؤُلَآءِ قَوْمٌۭ مُّجْرِمُونَ", transliteration: "FadaAAa rabbahu anna haolai qawmun mujrimoona", transliterationB: "Fada'aa rabbahooo anna haaa'ulaaa'i qawmum mujrimoon", english: "(But they were aggressive:) then he cried to his Lord: \"These are indeed a people given to sin", romanUrdu: "Aakhir e kaar usne apne Rubb ko pukara ke yeh log mujrim hain" },
    { number: 23, arabic: "فَأَسْرِ بِعِبَادِى لَيْلًا إِنَّكُم مُّتَّبَعُونَ", transliteration: "Faasri biAAibadee laylan innakum muttabaAAoona", transliterationB: "Fa asri bi'ibaadee lailan innakum muttaba'oon", english: "(The reply came:) \"March forth with My Servants by night: for ye are sure to be pursued", romanUrdu: "(Jawab diya gaya) accha to raat-o-raat mere bandon (servants) ko lekar chal padh. Tum logon ka peecha kiya jayega" },
    { number: 24, arabic: "وَٱتْرُكِ ٱلْبَحْرَ رَهْوًا ۖ إِنَّهُمْ جُندٌۭ مُّغْرَقُونَ", transliteration: "Waotruki albahra rahwan innahum jundun mughraqoona", transliterationB: "Watrukil bahra rahwan innahum jundum mughraqoon", english: "And leave the sea as a furrow (divided): for they are a host (destined) to be drowned", romanUrdu: "Samandar ko uske haal par khula chodh de.Yeh saara lashkar garq (drown) honay wala hai" },
    { number: 25, arabic: "كَمْ تَرَكُوا۟ مِن جَنَّٰتٍۢ وَعُيُونٍۢ", transliteration: "Kam tarakoo min jannatin waAAuyoonin", transliterationB: "Kam tarakoo min jannaatinw wa 'uyoon", english: "How many were the gardens and springs they left behind", romanUrdu: "Kitne hi baag aur chasme" },
    { number: 26, arabic: "وَزُرُوعٍۢ وَمَقَامٍۢ كَرِيمٍۢ", transliteration: "WazurooAAin wamaqamin kareemin", transliterationB: "Wa zuroo'inw wa maqaa min kareem", english: "And corn-fields and noble buildings", romanUrdu: "Aur kheit (gardens) aur shaandaar mahal thay jo woh chodh gaye" },
    { number: 27, arabic: "وَنَعْمَةٍۢ كَانُوا۟ فِيهَا فَٰكِهِينَ", transliteration: "WanaAAmatin kanoo feeha fakiheena", transliterationB: "Wa na'matin kaanoo feehaa faakiheen", english: "And wealth (and conveniences of life), wherein they had taken such delight", romanUrdu: "Kitne hi aish ke sar-o-samaan, jin mein woh mazey kar rahey thay unke pichey dharay reh gaye" },
    { number: 28, arabic: "كَذَٰلِكَ ۖ وَأَوْرَثْنَٰهَا قَوْمًا ءَاخَرِينَ", transliteration: "Kathalika waawrathnaha qawman akhareena", transliterationB: "Kazaalika wa awrasnaahaa qawman aakhareen", english: "Thus (was their end)! And We made other people inherit (those things)", romanUrdu: "Yeh hua unka anjaam, aur humne dusron ko in cheezon ka waris bana diya" },
    { number: 29, arabic: "فَمَا بَكَتْ عَلَيْهِمُ ٱلسَّمَآءُ وَٱلْأَرْضُ وَمَا كَانُوا۟ مُنظَرِينَ", transliteration: "Fama bakat AAalayhimu alssamao waalardu wama kanoo munthareena", transliterationB: "Famaa bakat 'alaihimus samaaa'u wal ardu wa maa kaanoo munzareen", english: "And neither heaven nor earth shed a tear over them: nor were they given a respite (again)", romanUrdu: "Phir na aasman unpar roya na zameen, aur zara si mohalat bhi unko na di gayi" },
    { number: 30, arabic: "وَلَقَدْ نَجَّيْنَا بَنِىٓ إِسْرَٰٓءِيلَ مِنَ ٱلْعَذَابِ ٱلْمُهِينِ", transliteration: "Walaqad najjayna banee israeela mina alAAathabi almuheeni", transliterationB: "Wa laqad najjainaa Baneee Israaa'eela minal'azaabil muheen", english: "We did deliver aforetime the Children of Israel from humiliating Punishment", romanUrdu: "Is taraah bani Israel ko humne sakht zillat ke azaab" },
    { number: 31, arabic: "مِن فِرْعَوْنَ ۚ إِنَّهُۥ كَانَ عَالِيًۭا مِّنَ ٱلْمُسْرِفِينَ", transliteration: "Min firAAawna innahu kana AAaliyan mina almusrifeena", transliterationB: "Min Fir'awn; innahoo kaana 'aaliyam minal musrifeen", english: "Inflicted by Pharaoh, for he was arrogant (even) among inordinate transgressors", romanUrdu: "Firoun se najaat di jo hadd se guzar janey walon mein fil waqeh badey unchey darje ka aadmi tha" },
    { number: 32, arabic: "وَلَقَدِ ٱخْتَرْنَٰهُمْ عَلَىٰ عِلْمٍ عَلَى ٱلْعَٰلَمِينَ", transliteration: "Walaqadi ikhtarnahum AAala AAilmin AAala alAAalameena", transliterationB: "Wa laqadikh tarnaahum 'alaa 'ilmin 'alal 'aalameen", english: "And We chose them aforetime above the nations, knowingly", romanUrdu: "Aur unki halat jaante huye, unko duniya ki dursi qaumon par tarjeeh di" },
    { number: 33, arabic: "وَءَاتَيْنَٰهُم مِّنَ ٱلْءَايَٰتِ مَا فِيهِ بَلَٰٓؤٌۭا۟ مُّبِينٌ", transliteration: "Waataynahum mina alayati ma feehi balaon mubeenun", transliterationB: "Wa aatainaahum minal aayaati maa feehi balaaa'um mubeen", english: "And granted them Signs in which there was a manifest trial", romanUrdu: "Aur unhein aisi nishaniya dikhayi jin mein sareeh aazmaish thi" },
    { number: 34, arabic: "إِنَّ هَٰٓؤُلَآءِ لَيَقُولُونَ", transliteration: "Inna haolai layaqooloona", transliterationB: "Inna haaa'ulaaa'i la yaqooloon", english: "As to these (Quraish), they say forsooth", romanUrdu: "Yeh log kehte hain" },
    { number: 35, arabic: "إِنْ هِىَ إِلَّا مَوْتَتُنَا ٱلْأُولَىٰ وَمَا نَحْنُ بِمُنشَرِينَ", transliteration: "In hiya illa mawtatuna aloola wama nahnu bimunshareena", transliterationB: "In hiya illaa mawtatunal oolaa wa maa nahnu bimun shareen", english: "There is nothing beyond our first death, and we shall not be raised again", romanUrdu: "“hamari pehli maut ke siwa aur kuch nahin uske baad hum dobara uthaye jaane wale nahin hai" },
    { number: 36, arabic: "فَأْتُوا۟ بِـَٔابَآئِنَآ إِن كُنتُمْ صَٰدِقِينَ", transliteration: "Fatoo biabaina in kuntum sadiqeena", transliterationB: "Faatoo bi aabaaa'inaaa inkuntum saadiqeen", english: "Then bring (back) our forefathers, if what ye say is true", romanUrdu: "Agar tum sacchey ho to utha lao hamare baap dada ko”" },
    { number: 37, arabic: "أَهُمْ خَيْرٌ أَمْ قَوْمُ تُبَّعٍۢ وَٱلَّذِينَ مِن قَبْلِهِمْ ۚ أَهْلَكْنَٰهُمْ ۖ إِنَّهُمْ كَانُوا۟ مُجْرِمِينَ", transliteration: "Ahum khayrun am qawmu tubbaAAin waallatheena min qablihim ahlaknahum innahum kanoo mujrimeena", transliterationB: "Ahum khayrun am qawmu Tubba'inw wallazeena min qablihim; ahlaknaahum innahum kaanoo mujrimeen", english: "What! Are they better than the people of Tubba and those who were before them? We destroyed them because they were guilty of sin", romanUrdu: "Yeh behtar hai ya tubbah ki qaum aur ussey pehle ke log? Humne unko isi bina par tabah kiya ke woh mujrim ho gaye thay" },
    { number: 38, arabic: "وَمَا خَلَقْنَا ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ وَمَا بَيْنَهُمَا لَٰعِبِينَ", transliteration: "Wama khalaqna alssamawati waalarda wama baynahuma laAAibeena", transliterationB: "Wa maa khalaqnas samaawaati wal arda wa maa baina humaa laa'ibeen", english: "We created not the heavens, the earth, and all between them, merely in (idle) sport", romanUrdu: "Yeh Aasman o zameen aur inke darmiyan ki cheezein humne kuch khel ke taur par nahin bana di hai" },
    { number: 39, arabic: "مَا خَلَقْنَٰهُمَآ إِلَّا بِٱلْحَقِّ وَلَٰكِنَّ أَكْثَرَهُمْ لَا يَعْلَمُونَ", transliteration: "Ma khalaqnahuma illa bialhaqqi walakinna aktharahum la yaAAlamoona", transliterationB: "Maa khalaqnaahumaaa illaa bilhaqqi wa laakinna aksarahum laa ya'lamoon", english: "We created them not except for just ends: but most of them do not understand", romanUrdu: "Inko humne bar-haqq paida kiya hai, magar aksar log jaante hain hai" },
    { number: 40, arabic: "إِنَّ يَوْمَ ٱلْفَصْلِ مِيقَٰتُهُمْ أَجْمَعِينَ", transliteration: "Inna yawma alfasli meeqatuhum ajmaAAeena", transliterationB: "Inna yawmal fasli meeqaatuhum ajma'een", english: "Verily the Day of sorting out is the time appointed for all of them", romanUrdu: "In sabke uthaye janey ke liye the-shuda waqt faisle ka din hai" },
    { number: 41, arabic: "يَوْمَ لَا يُغْنِى مَوْلًى عَن مَّوْلًۭى شَيْـًۭٔا وَلَا هُمْ يُنصَرُونَ", transliteration: "Yawma la yughnee mawlan AAan mawlan shayan wala hum yunsaroona", transliterationB: "Yawma laa yughnee mawlan 'am mawlan shai'anw wa laa hum yunsaroon", english: "The Day when no protector can avail his client in aught, and no help can they receive", romanUrdu: "Woh din jab koi azeez kareeb apne kisi azeez kareeb ke kuch bhi kaam nahin aayega. Aur na kahin se unhein koi madad pahunchegi" },
    { number: 42, arabic: "إِلَّا مَن رَّحِمَ ٱللَّهُ ۚ إِنَّهُۥ هُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ", transliteration: "Illa man rahima Allahu innahu huwa alAAazeezu alrraheemu", transliterationB: "Illaa mar rahimal laah' innahoo huwal 'azeezur raheem", english: "Except such as receive Allah's Mercy: for He is Exalted in Might, Most Merciful", romanUrdu: "Siwaye iske ke Allah hi kisi par reham karey, woh zabardast aur Raheem hai" },
    { number: 43, arabic: "إِنَّ شَجَرَتَ ٱلزَّقُّومِ", transliteration: "Inna shajarata alzzaqqoomi", transliterationB: "Inna shajarataz zaqqoom", english: "Verily the tree of Zaqqum", romanUrdu: "Zakkhum ka darakht (tree)" },
    { number: 44, arabic: "طَعَامُ ٱلْأَثِيمِ", transliteration: "TaAAamu alatheemi", transliterationB: "Ta'aamul aseem", english: "Will be the food of the Sinful", romanUrdu: "Gunahgaar ka kha-ja (khana /food) hoga" },
    { number: 45, arabic: "كَٱلْمُهْلِ يَغْلِى فِى ٱلْبُطُونِ", transliteration: "Kaalmuhli yaghlee fee albutooni", transliterationB: "Kalmuhli yaghlee filbutoon", english: "Like molten brass; it will boil in their insides", romanUrdu: "Tail (oil) ki tiljhat (dregs) jaisa, pait (bellies) mein is tarah josh khayega" },
    { number: 46, arabic: "كَغَلْىِ ٱلْحَمِيمِ", transliteration: "Kaghalyi alhameemi", transliterationB: "Kaghalyil hameem", english: "Like the boiling of scalding water", romanUrdu: "Jaise khaulta (boiling) hua pani josh khata hai" },
    { number: 47, arabic: "خُذُوهُ فَٱعْتِلُوهُ إِلَىٰ سَوَآءِ ٱلْجَحِيمِ", transliteration: "Khuthoohu faiAAtiloohu ila sawai aljaheemi", transliterationB: "Khuzoohu fa'tiloohu ilaa sawaaa'il Jaheem", english: "A voice will cry: \"Seize ye him and drag him into the midst of the Blazing Fire", romanUrdu: "Pakado isey aur raged-te (dragging) huey le jao isko jahannum ke beechon beech" },
    { number: 48, arabic: "ثُمَّ صُبُّوا۟ فَوْقَ رَأْسِهِۦ مِنْ عَذَابِ ٱلْحَمِيمِ", transliteration: "Thumma subboo fawqa rasihi min AAathabi alhameemi", transliterationB: "Summa subboo fawqa raasihee min 'azaabil hameem", english: "Then pour over his head the Penalty of Boiling Water", romanUrdu: "Aur undhail (pour) do iske sar par khaulte (boiling) paani ka azaab" },
    { number: 49, arabic: "ذُقْ إِنَّكَ أَنتَ ٱلْعَزِيزُ ٱلْكَرِيمُ", transliteration: "Thuq innaka anta alAAazeezu alkareemu", transliterationB: "Zuq innaka antal 'azeezul kareem", english: "Taste thou (this)! Truly wast thou mighty, full of honour", romanUrdu: "Chakkh iska maza, bada zabardast izzatdaar aadmi hai tu" },
    { number: 50, arabic: "إِنَّ هَٰذَا مَا كُنتُم بِهِۦ تَمْتَرُونَ", transliteration: "Inna hatha ma kuntum bihi tamtaroona", transliterationB: "Inna haazaa maa kuntum bihee tamtaroon", english: "Truly this is what ye used to doubt", romanUrdu: "Yeh wahi cheez hai jiske aane mein tumlog shakk rakhte thay”" },
    { number: 51, arabic: "إِنَّ ٱلْمُتَّقِينَ فِى مَقَامٍ أَمِينٍۢ", transliteration: "Inna almuttaqeena fee maqamin ameenin", transliterationB: "Innal muttaqeena fee maqaamin ameen", english: "As to the Righteous (they will be) in a position of Security", romanUrdu: "Khuda tars log aman ki jagah mein hongey" },
    { number: 52, arabic: "فِى جَنَّٰتٍۢ وَعُيُونٍۢ", transliteration: "Fee jannatin waAAuyoonin", transliterationB: "Fee jannaatinw wa 'uyoon", english: "Among Gardens and Springs", romanUrdu: "Baaghon (gardens) aur chashmo mein" },
    { number: 53, arabic: "يَلْبَسُونَ مِن سُندُسٍۢ وَإِسْتَبْرَقٍۢ مُّتَقَٰبِلِينَ", transliteration: "Yalbasoona min sundusin waistabraqin mutaqabileena", transliterationB: "Yalbasoona min sundusinw wa istbraqim mutaqaabileen", english: "Dressed in fine silk and in rich brocade, they will face each other", romanUrdu: "Hareer-o-deeba (silk and brocade) ke libas pehne, aamne saamne baithey honge" },
    { number: 54, arabic: "كَذَٰلِكَ وَزَوَّجْنَٰهُم بِحُورٍ عِينٍۢ", transliteration: "Kathalika wazawwajnahum bihoorin AAeenin", transliterationB: "Kazaalika wa zawwajnaahum bihoorin 'een", english: "So; and We shall join them to fair women with beautiful, big, and lustrous eyes", romanUrdu: "Yeh hogi inki shaan aur hum gori gori aah-o-chashm auratein unse biyah denge" },
    { number: 55, arabic: "يَدْعُونَ فِيهَا بِكُلِّ فَٰكِهَةٍ ءَامِنِينَ", transliteration: "YadAAoona feeha bikulli fakihatin amineena", transliterationB: "Yad'oona feehaa bikulli faakihatin aamineen", english: "There can they call for every kind of fruit in peace and security", romanUrdu: "Wahan woh itminaan se har tarah ki lazeez cheezein talab karenge" },
    { number: 56, arabic: "لَا يَذُوقُونَ فِيهَا ٱلْمَوْتَ إِلَّا ٱلْمَوْتَةَ ٱلْأُولَىٰ ۖ وَوَقَىٰهُمْ عَذَابَ ٱلْجَحِيمِ", transliteration: "La yathooqoona feeha almawta illa almawtata aloola wawaqahum AAathaba aljaheemi", transliterationB: "Laa yazooqoona feehal mawtaa illal mawtatal oolaa wa qaqaahum 'azaabal jaheem", english: "Nor will they there taste Death, except the first death; and He will preserve them from the Penalty of the Blazing Fire", romanUrdu: "Wahan maut ka maza woh kabhi na chakhenge . Bas duniya mein jo maut aa chuki so aa chuki aur Allah apne fazal se" },
    { number: 57, arabic: "فَضْلًۭا مِّن رَّبِّكَ ۚ ذَٰلِكَ هُوَ ٱلْفَوْزُ ٱلْعَظِيمُ", transliteration: "Fadlan min rabbika thalika huwa alfawzu alAAatheemu", transliterationB: "Fadlam mir rabbik; zaalika huwal fawzul 'azeem", english: "As a Bounty from thy Lord! that will be the supreme achievement", romanUrdu: "Unko jahannum ke azaab se bacha dega yahi badi kamiyabi hai" },
    { number: 58, arabic: "فَإِنَّمَا يَسَّرْنَٰهُ بِلِسَانِكَ لَعَلَّهُمْ يَتَذَكَّرُونَ", transliteration: "Fainnama yassarnahu bilisanika laAAallahum yatathakkaroona", transliterationB: "Fa innamaa yassarnaahu bilisaanika la'allahum yatazakkaroon", english: "Verily, We have made this (Qur'an) easy, in thy tongue, in order that they may give heed", romanUrdu: "Aey Nabi (s.a.s) humne is kitaab ko tumhari zubaan mein sahal (easy / aasaan) bana diya hai taake yeh log nasihat hasil karein" },
    { number: 59, arabic: "فَٱرْتَقِبْ إِنَّهُم مُّرْتَقِبُونَ", transliteration: "Fairtaqib innahum murtaqiboona", transliterationB: "Fartaqib innahum murta qiboon", english: "So wait thou and watch; for they (too) are waiting", romanUrdu: "Ab tum bhi intezar karo, yeh bhi muntazir (intezar kar rahey) hain" }
  ]
};
